  expect_true(if (is.character(result$content)) length(result$content) > 0 && any(nchar(result$content) > 0) else length(result$content) > 0)
  expect_true(grepl("Image", result$content, fixed = TRUE))
})

test_that("options_max_image_size_tiny_limit_safe: A tiny max_image_size does not crash conversion even when the image exceeds the limit", {
  result <- convert(html = "<p>Tiny limit: <img src=\"data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mP8/5+hHgAHggJ/PchI7wAAAABJRU5ErkJggg==\" alt=\"pixel\"></p>", options = ConversionOptions$from_json(jsonlite::toJSON(list("extract_images" = TRUE, "max_image_size" = 10), auto_unbox = TRUE)))
  expect_true(if (is.character(result$content)) length(result$content) > 0 && any(nchar(result$content) > 0) else length(result$content) > 0)
  expect_true(grepl("Tiny limit", result$content, fixed = TRUE))
})

test_that("options_newline_backslash: Hard line breaks rendered with backslash", {
  result <- convert(html = "<p>Line one<br>Line two</p>", options = ConversionOptions$from_json(jsonlite::toJSON(list("newline_style" = "backslash"), auto_unbox = TRUE)))
  expect_true(any(grepl("Line one", result$content, fixed = TRUE)))
  expect_true(any(grepl("Line two", result$content, fixed = TRUE)))
})

test_that("options_newline_spaces: Hard line breaks rendered with trailing spaces", {
  result <- convert(html = "<p>First<br>Second</p>", options = ConversionOptions$from_json(jsonlite::toJSON(list("newline_style" = "spaces"), auto_unbox = TRUE)))
  expect_true(any(grepl("First", result$content, fixed = TRUE)))
  expect_true(any(grepl("Second", result$content, fixed = TRUE)))
})

test_that("options_output_format_djot: Djot output format produces djot-compatible markup", {
  result <- convert(html = "<p>Simple paragraph.</p>", options = ConversionOptions$from_json(jsonlite::toJSON(list("output_format" = "djot"), auto_unbox = TRUE)))
  expect_true(if (is.character(result$content)) length(result$content) > 0 && any(nchar(result$content) > 0) else length(result$content) > 0)
  expect_true(any(grepl("Simple paragraph.", result$content, fixed = TRUE)))
})

test_that("options_output_format_markdown: Default markdown output format produces standard markdown", {
  result <- convert(html = "<h1>Title</h1><p>Some text.</p>", options = ConversionOptions$from_json(jsonlite::toJSON(list("heading_style" = "atx", "output_format" = "markdown"), auto_unbox = TRUE)))
  expect_true(any(grepl("# Title", result$content, fixed = TRUE)))
  expect_true(any(grepl("Some text.", result$content, fixed = TRUE)))
})

test_that("options_output_format_plain: Plain text output format strips markdown syntax", {
  result <- convert(html = "<h1>Title</h1><p>Some <strong>bold</strong> text.</p>", options = ConversionOptions$from_json(jsonlite::toJSON(list("output_format" = "plain"), auto_unbox = TRUE)))
  expect_true(any(grepl("Title", result$content, fixed = TRUE)))
  expect_true(any(grepl("bold", result$content, fixed = TRUE)))
  expect_true(any(grepl("text.", result$content, fixed = TRUE)))
})

test_that("options_preprocessing_aggressive: Aggressive preset removes nav, footer, aside unconditionally", {
  result <- convert(html = "<nav>Menu</nav><article><h1>Title</h1><p>Content</p></article><aside>Sidebar</aside><footer>Footer</footer>", options = ConversionOptions$from_json(jsonlite::toJSON(list("preprocessing" = list("preset" = "aggressive")), auto_unbox = TRUE)))
  expect_true(any(grepl("Title", result$content, fixed = TRUE)))
  expect_true(any(grepl("Content", result$content, fixed = TRUE)))
  expect_false(grepl("Menu", result$content, fixed = TRUE))
})

test_that("options_preprocessing_enabled_false_skips_cleanup: Disabling preprocessing entirely preserves elements the standard preset would remove", {
  result <- convert(html = "<nav>NavSection</nav><p>Paragraph</p>", options = ConversionOptions$from_json(jsonlite::toJSON(list("preprocessing" = list("enabled" = FALSE)), auto_unbox = TRUE)))
  expect_true(any(grepl("NavSection", result$content, fixed = TRUE)))
  expect_true(any(grepl("Paragraph", result$content, fixed = TRUE)))
})

test_that("options_preprocessing_minimal: Minimal preset preserves nav, footer, aside", {
  result <- convert(html = "<nav>Navigation</nav><p>Content</p><footer>Footer</footer>", options = ConversionOptions$from_json(jsonlite::toJSON(list("preprocessing" = list("preset" = "minimal")), auto_unbox = TRUE)))
  expect_true(any(grepl("Navigation", result$content, fixed = TRUE)))
  expect_true(any(grepl("Content", result$content, fixed = TRUE)))
  expect_true(any(grepl("Footer", result$content, fixed = TRUE)))
})

test_that("options_preprocessing_remove_forms: Forms are removed when remove_forms is true", {
  result <- convert(html = "<p>Before</p><form><input type='text'/><button>Submit</button></form><p>After</p>", options = ConversionOptions$from_json(jsonlite::toJSON(list("preprocessing" = list("remove_forms" = TRUE)), auto_unbox = TRUE)))
  expect_true(any(grepl("Before", result$content, fixed = TRUE)))
  expect_true(any(grepl("After", result$content, fixed = TRUE)))
  expect_false(grepl("Submit", result$content, fixed = TRUE))
})

test_that("options_preprocessing_remove_navigation_false_keeps_nav: Setting remove_navigation to false preserves nav and aside elements", {
  result <- convert(html = "<nav>SiteMenu</nav><main><p>MainContent</p></main><aside>SidebarText</aside>", options = ConversionOptions$from_json(jsonlite::toJSON(list("preprocessing" = list("remove_navigation" = FALSE)), auto_unbox = TRUE)))
  expect_true(any(grepl("SiteMenu", result$content, fixed = TRUE)))
  expect_true(any(grepl("MainContent", result$content, fixed = TRUE)))
  expect_true(any(grepl("SidebarText", result$content, fixed = TRUE)))
})

test_that("options_preserve_tags_iframe: Iframe tags preserved as raw HTML in output", {
  result <- convert(html = "<p>Before</p><iframe src='video.html' width='560'></iframe><p>After</p>", options = ConversionOptions$from_json(jsonlite::toJSON(list("preserve_tags" = I(c("iframe"))), auto_unbox = TRUE)))
  expect_true(any(grepl("Before", result$content, fixed = TRUE)))
  expect_true(any(grepl("After", result$content, fixed = TRUE)))
  expect_true(any(grepl("<iframe", result$content, fixed = TRUE)))
})

test_that("options_skip_images_true: Images are omitted from output when skipImages is true", {
  result <- convert(html = "<p>Before <img src='test.jpg' alt='photo'> After</p>", options = ConversionOptions$from_json(jsonlite::toJSON(list("skip_images" = TRUE), auto_unbox = TRUE)))
  expect_true(any(grepl("Before", result$content, fixed = TRUE)))
  expect_true(any(grepl("After", result$content, fixed = TRUE)))
  expect_false(grepl("photo", result$content, fixed = TRUE))
})

test_that("options_strip_newlines: Strip newlines produces single-line paragraphs", {
  result <- convert(html = "<p>First paragraph.</p><p>Second paragraph.</p>", options = ConversionOptions$from_json(jsonlite::toJSON(list("strip_newlines" = TRUE), auto_unbox = TRUE)))
  expect_true(any(grepl("First paragraph.", result$content, fixed = TRUE)))
  expect_true(any(grepl("Second paragraph.", result$content, fixed = TRUE)))
})

test_that("options_strip_tags_div_span: Div and span tags stripped but content preserved", {
  result <- convert(html = "<div class='wrapper'><p>Inside div</p></div><p>Outside <span class='hl'>span text</span></p>", options = ConversionOptions$from_json(jsonlite::toJSON(list("strip_tags" = I(c("div", "span"))), auto_unbox = TRUE)))
  expect_true(any(grepl("Inside div", result$content, fixed = TRUE)))
  expect_true(any(grepl("span text", result$content, fixed = TRUE)))
})

test_that("options_strong_em_underscore: Strong and em tags use underscore symbol instead of asterisk", {
  result <- convert(html = "<p><strong>bold</strong> and <em>italic</em></p>", options = ConversionOptions$from_json(jsonlite::toJSON(list("strong_em_symbol" = "_"), auto_unbox = TRUE)))
  expect_true(any(grepl("__bold__", result$content, fixed = TRUE)))
  expect_true(any(grepl("_italic_", result$content, fixed = TRUE)))
})

test_that("options_sub_symbol_tilde: Subscript rendered with tilde symbol", {
  result <- convert(html = "<p>H<sub>2</sub>O</p>", options = ConversionOptions$from_json(jsonlite::toJSON(list("sub_symbol" = "~"), auto_unbox = TRUE)))
  expect_true(any(grepl("~2~", result$content, fixed = TRUE)))
})

test_that("options_sup_symbol_caret: Superscript rendered with caret symbol", {
  result <- convert(html = "<p>x<sup>2</sup></p>", options = ConversionOptions$from_json(jsonlite::toJSON(list("sup_symbol" = "^"), auto_unbox = TRUE)))
  expect_true(any(grepl("^2^", result$content, fixed = TRUE)))
})

test_that("options_url_escape_style_angle_default: Default angle style wraps URLs containing spaces in angle brackets", {
  result <- convert(html = "<a href=\"/file (1).pdf\">file</a>", options = ConversionOptions$from_json(jsonlite::toJSON(list("url_escape_style" = "angle"), auto_unbox = TRUE)))
  expect_true(grepl("</file (1).pdf>", result$content, fixed = TRUE))
})

test_that("options_url_escape_style_percent_angle_brackets_in_url: Percent style encodes angle brackets in link URLs from issue 392", {
  result <- convert(html = "<a href=\"/file (1) <draft>.pdf\">file</a>", options = ConversionOptions$from_json(jsonlite::toJSON(list("url_escape_style" = "percent"), auto_unbox = TRUE)))
  expect_true(grepl("/file%20%281%29%20%3Cdraft%3E.pdf", result$content, fixed = TRUE))
})

test_that("options_url_escape_style_percent_image: Percent style encodes special characters in image src URLs", {
  result <- convert(html = "<img src=\"/img (1) <draft>.png\" alt=\"alt\">", options = ConversionOptions$from_json(jsonlite::toJSON(list("url_escape_style" = "percent"), auto_unbox = TRUE)))
  expect_true(grepl("/img%20%281%29%20%3Cdraft%3E.png", result$content, fixed = TRUE))
})

test_that("options_url_escape_style_percent_link: Percent style encodes spaces and parens in link URLs", {
  result <- convert(html = "<a href=\"/file (1).pdf\">file</a>", options = ConversionOptions$from_json(jsonlite::toJSON(list("url_escape_style" = "percent"), auto_unbox = TRUE)))
  expect_true(grepl("/file%20%281%29.pdf", result$content, fixed = TRUE))
  expect_false(grepl("</", result$content, fixed = TRUE))
})

test_that("options_whitespace_normalized: Normalized whitespace mode collapses multiple spaces", {
  result <- convert(html = "<p>Text   with    extra   spaces.</p>", options = ConversionOptions$from_json(jsonlite::toJSON(list("whitespace_mode" = "normalized"), auto_unbox = TRUE)))
  expect_true(if (is.character(result$content)) length(result$content) > 0 && any(nchar(result$content) > 0) else length(result$content) > 0)
  expect_true(any(grepl("Text", result$content, fixed = TRUE)))
  expect_true(any(grepl("with", result$content, fixed = TRUE)))
  expect_true(any(grepl("extra", result$content, fixed = TRUE)))
  expect_true(any(grepl("spaces.", result$content, fixed = TRUE)))
})

test_that("options_whitespace_strict: Strict whitespace mode preserves whitespace as-is", {
  result <- convert(html = "<p>Preserved   spacing.</p>", options = ConversionOptions$from_json(jsonlite::toJSON(list("whitespace_mode" = "strict"), auto_unbox = TRUE)))
  expect_true(if (is.character(result$content)) length(result$content) > 0 && any(nchar(result$content) > 0) else length(result$content) > 0)
  expect_true(any(grepl("Preserved", result$content, fixed = TRUE)))
  expect_true(any(grepl("spacing.", result$content, fixed = TRUE)))
})

test_that("options_wrap_disabled: Wrap option disabled preserves long lines without breaking", {
  result <- convert(html = "<p>This is a long paragraph that should not be wrapped at all because wrapping is disabled.</p>", options = ConversionOptions$from_json(jsonlite::toJSON(list("wrap" = FALSE), auto_unbox = TRUE)))
  expect_true(any(grepl("This is a long paragraph that should not be wrapped at all because wrapping is disabled.", result$content, fixed = TRUE)))
})

test_that("options_wrap_enabled: Wrap option enabled with custom width wraps long lines", {
  result <- convert(html = "<p>This is a long paragraph that should be wrapped at the specified column width when the wrap option is enabled.</p>", options = ConversionOptions$from_json(jsonlite::toJSON(list("wrap" = TRUE, "wrap_width" = 40), auto_unbox = TRUE)))
  expect_true(if (is.character(result$content)) length(result$content) > 0 && any(nchar(result$content) > 0) else length(result$content) > 0)
  expect_true(any(grepl("This is a long paragraph", result$content, fixed = TRUE)))
})
